// menu.js
import { useState, useEffect } from "react";

export default function Menu() {
  // نصوص القائمة المتحركة في المنتصف
  const texts = ["مرحباً بكم", "أهلاً وسهلاً", "تفضلوا", "استمتعوا"];
  const [index, setIndex] = useState(0);

  // حركة الماوس للكاردات
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  // الكاردات (المنتجات)
  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png", side: "left" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png", side: "left" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png", side: "right" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png", side: "right" }
  ];

  // تغيير النص في المنتصف
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % texts.length);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  // تتبع حركة الماوس
  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 40,
        y: (e.clientY / window.innerHeight - 0.5) * 40
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #0f0c29, #302b63, #24243e)",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* خلفية متحركة */}
      <div style={{
        position: "absolute",
        width: "100%",
        height: "100%",
        background: "radial-gradient(circle at 50% 50%, rgba(34,197,94,0.1) 0%, transparent 70%)",
        pointerEvents: "none"
      }}></div>

      {/* الكاردات اليسرى */}
      <div style={{
        position: "fixed",
        left: "30px",
        top: "50%",
        transform: `translateY(-50%) translateX(${mousePosition.x * 0.5}px)`,
        display: "flex",
        flexDirection: "column",
        gap: "20px",
        zIndex: 10,
        transition: "transform 0.1s ease-out"
      }}>
        {cards.filter(c => c.side === "left").map((card) => (
          <div key={card.id} style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}dd)`,
            width: "120px",
            padding: "20px",
            borderRadius: "20px",
            textAlign: "center",
            cursor: "pointer",
            boxShadow: "0 10px 30px rgba(0,0,0,0.3)",
            transition: "all 0.3s ease",
            backdropFilter: "blur(10px)",
            border: "1px solid rgba(255,255,255,0.2)"
          }}
          onMouseEnter={(e) => e.currentTarget.style.transform = "scale(1.05) translateX(10px)"}
          onMouseLeave={(e) => e.currentTarget.style.transform = "scale(1) translateX(0)"}
          >
            <img src={card.image} alt={card.name} style={{ width: "60px", height: "60px", marginBottom: "10px" }} />
            <h3 style={{ color: "white", margin: 0, fontSize: "1.2rem" }}>{card.name}</h3>
            <span style={{ fontSize: "2rem" }}>{card.icon}</span>
          </div>
        ))}
      </div>

      {/* الكاردات اليمنى */}
      <div style={{
        position: "fixed",
        right: "30px",
        top: "50%",
        transform: `translateY(-50%) translateX(${mousePosition.x * 0.5}px)`,
        display: "flex",
        flexDirection: "column",
        gap: "20px",
        zIndex: 10,
        transition: "transform 0.1s ease-out"
      }}>
        {cards.filter(c => c.side === "right").map((card) => (
          <div key={card.id} style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}dd)`,
            width: "120px",
            padding: "20px",
            borderRadius: "20px",
            textAlign: "center",
            cursor: "pointer",
            boxShadow: "0 10px 30px rgba(0,0,0,0.3)",
            transition: "all 0.3s ease",
            backdropFilter: "blur(10px)",
            border: "1px solid rgba(255,255,255,0.2)"
          }}
          onMouseEnter={(e) => e.currentTarget.style.transform = "scale(1.05) translateX(-10px)"}
          onMouseLeave={(e) => e.currentTarget.style.transform = "scale(1) translateX(0)"}
          >
            <img src={card.image} alt={card.name} style={{ width: "60px", height: "60px", marginBottom: "10px" }} />
            <h3 style={{ color: "white", margin: 0, fontSize: "1.2rem" }}>{card.name}</h3>
            <span style={{ fontSize: "2rem" }}>{card.icon}</span>
          </div>
        ))}
      </div>

      {/* القائمة في المنتصف */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.3}px, ${mousePosition.y * 0.3}px)`,
        textAlign: "center",
        zIndex: 20,
        transition: "transform 0.1s ease-out"
      }}>
        <div style={{
          background: "rgba(0,0,0,0.6)",
          backdropFilter: "blur(20px)",
          padding: "40px 60px",
          borderRadius: "30px",
          border: "2px solid rgba(34,197,94,0.5)",
          boxShadow: "0 0 50px rgba(34,197,94,0.3)"
        }}>
          <h1 style={{
            fontSize: "3.5rem",
            fontWeight: "bold",
            background: "linear-gradient(135deg, #ffffff, #22c55e)",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            margin: 0
          }}>
            {texts[index]}
          </h1>
          <p style={{ color: "#ccc", marginTop: "15px", fontSize: "1.2rem" }}>
            اختر ما تفضله
          </p>
          <div style={{
            width: "50px",
            height: "2px",
            background: "#22c55e",
            margin: "20px auto 0",
            borderRadius: "10px"
          }}></div>
        </div>
      </div>

      {/* تأثير الجزيئات */}
      <div style={{
        position: "fixed",
        bottom: "20px",
        left: 0,
        right: 0,
        textAlign: "center",
        color: "rgba(255,255,255,0.5)",
        fontSize: "12px",
        zIndex: 30
      }}>
        ✨ حرك الماوس لتتحرك الكاردات ✨
      </div>
    </div>
  );
}
